                        )}
                        
                        <button onClick={handleConfirmMoveToCart} className="w-full bg-rich-black text-white py-3 mt-4 text-xs uppercase tracking-widest font-medium hover:bg-gold transition-colors">
                          Confirm & Add
                        </button>
                      </div>
                    );
                  })()}
                </div>
              </div>
            )}
            
          </main>
        </div>
      </div>
    </div>
