"use client";

import { useState, useEffect, use } from "react";
import { useRouter } from "next/navigation";
import { createClient } from "@/utils/supabase/client";
import { ArrowLeft, Save, Image as ImageIcon, Trash2 } from "lucide-react";
import Link from "next/link";
import ImageUploader from "@/components/admin/ImageUploader";
import { toast } from "@/store/useToastStore";

export default function EditCategoryPage({ params: paramsPromise }: { params: Promise<{ id: string }> }) {
  const params = use(paramsPromise);
  const supabase = createClient();
  const router = useRouter();
  const [saving, setSaving] = useState(false);
  const [fetching, setFetching] = useState(true);
  
  const [formData, setFormData] = useState({
    name: "",
    slug: "",
    description: "",
    image_url: "",
    is_active: true,
    display_order: 0
  });

  useEffect(() => {
    const fetchCategory = async () => {
      setFetching(true);
      const { data, error } = await supabase.from('categories').select('*').eq('id', params.id).single();
      
      if (data) {
        setFormData({
          name: data.name || "",
          slug: data.slug || "",
          description: data.description || "",
          image_url: data.image_url || "",
          is_active: data.is_active ?? true,
          display_order: data.display_order || 0
        });
      } else {
        toast.error("Category not found");
        router.push("/admin/categories");
      }
      setFetching(false);
    };

    fetchCategory();
  }, [params.id, router]);

  const handleSave = async () => {
    try {
      setSaving(true);
      
      const { error } = await supabase
        .from("categories")
        .update(formData)
        .eq('id', params.id);

      if (error) throw error;
      
      router.push("/admin/categories");
    } catch (error: any) {
      console.error("Error updating category:", error);
      toast.error("Failed to complete operation. Please try again or check the logs.");
    } finally {
      setSaving(false);
    }
  };

  if (fetching) {
