                          <div className="mt-auto pt-2">
                            <p className="text-[10px] uppercase tracking-widest text-neutral-400 font-medium">Qty: {item.quantity}</p>
                          </div>
                        )}
                      </div>
                    </div>
                  ))
                )}
              </div>

              {/* Discount Code */}
              <div className="mb-8 border-t border-border-light pt-8">
