export default async function Home() {
  const supabase = await createClient();

  // Fetch Homepage Sections
  let sections: any[] = [];
  try {
    const { data, error } = await supabase
      .from("homepage_sections")
      .select("*")
      .eq("is_active", true)
      .order("display_order", { ascending: true });
    if (data && !error) sections = data;
  } catch (error) {
    console.error("Error fetching homepage sections:", error);
  }

  const heroSlides = sections?.filter(s => s.section_type === 'hero').map(s => ({
    id: s.id,
    image_url: s.image_url || "",
    title: s.title,
    subtitle: s.subtitle || ""
  })) || [];

  const trendingEdits = sections?.filter(s => s.section_type === 'trending').map((s, index, arr) => {
    // Dynamic styling based on total number of items to ensure no empty spaces
    let className = "col-span-1 row-span-1 aspect-square"; // fallback

    if (arr.length === 1) {
      className = "col-span-1 md:col-span-4 row-span-2 aspect-[16/9] md:aspect-[21/9]";
    } else if (arr.length === 2) {
      className = "col-span-1 md:col-span-2 row-span-2 aspect-[4/5]";
    } else if (arr.length === 3) {
      if (index === 0) className = "col-span-1 md:col-span-2 row-span-2 aspect-[3/4] md:aspect-auto";
      else className = "col-span-1 md:col-span-2 row-span-1 aspect-[16/9]";
    } else if (arr.length === 4) {
      if (index === 0) className = "col-span-1 md:col-span-2 row-span-2 aspect-[3/4] md:aspect-[4/5]";
      else if (index === 1 || index === 2) className = "col-span-1 md:col-span-1 row-span-1 aspect-square";
      else if (index === 3) className = "col-span-1 md:col-span-2 row-span-1 aspect-[16/9] md:aspect-[21/9]";
    } else {
      // 5 or more items
      if (index === 0) className = "col-span-1 md:col-span-2 row-span-2 aspect-[3/4] md:aspect-[4/5]";
      else if (index % 5 === 4) className = "col-span-1 md:col-span-2 row-span-1 aspect-[16/9] md:aspect-[21/9]";
      else className = "col-span-1 md:col-span-1 row-span-1 aspect-square";
    }

    return {
      id: s.id,
      title: s.title,
      slug: s.subtitle || 'all',
      image: s.image_url || "",
      className
    };
  }) || [];

  const editorialStories = sections?.filter(s => s.section_type === 'editorial').map(s => ({
    id: s.id,
    title: s.title,
    description: s.subtitle || "",
    image: s.image_url || "",
    align: s.button_text || 'left'
  })) || [];

  const testimonials = sections?.filter(s => s.section_type === 'testimonial').map(s => ({
    id: s.id,
    name: s.title,
    text: s.subtitle,
    product: s.button_text,
    image: s.image_url
  })) || [];

  // Fetch Categories
  let categories: any[] = [];
  try {
    const { data, error } = await supabase
      .from("categories")
      .select("*")
      .eq("is_active", true)
      .order("display_order", { ascending: true });
    if (data && !error) categories = data;
  } catch (error) {
    console.error("Error fetching categories:", error);
  }

  const mappedCategories = categories?.map(c => ({
    id: c.id,
    title: c.name,
    image: c.image_url || "",
    link: `/collections/${c.slug}`
  })) || [];

  // Fetch Best Sellers
  let bestSellers: any[] = [];
  try {
    const { data, error } = await supabase
      .from("products")
      .select("*, product_images(url, color_name), product_variants(color_name, size)")
      .eq("is_bestseller", true)
      .eq("status", "active")
      .limit(10);

    if (!error && data) {
      bestSellers = data;
    } else if (error) {
      console.error("Error fetching bestsellers:", error);
    }
  } catch (error) {
    console.error("Error fetching bestsellers:", error);
  }

  const mappedBestSellers = bestSellers?.map(p => {
    const images = p.product_images?.map((img: any) => img.url) || [];
    const colorsMap = new Map<string, string>();
    if (p.product_variants) {
      p.product_variants.forEach((v: any) => {
        if (!colorsMap.has(v.color_name)) {
          const matchingImg = p.product_images?.find((img: any) => img.color_name === v.color_name);
          colorsMap.set(v.color_name, matchingImg?.url || images[0]);
        }
      });
    }
    const sizesSet = new Set<string>();
    if (p.product_variants) {
      p.product_variants.forEach((v: any) => {
        if (v.size) sizesSet.add(v.size);
      });
    }

    return {
      id: p.id,
      slug: p.slug,
      name: p.name,
      price: p.price,
      images,
      colors: Array.from(colorsMap.entries()).map(([name, image]) => ({ name, image })),
      sizes: Array.from(sizesSet),
      isNew: p.is_featured,
      isSale: (p.compare_at_price ?? 0) > p.price
    };
  }) || [];

  // Fetch Featured (New Collection)
  let featuredProducts: any[] = [];
  try {
    const { data, error } = await supabase
      .from("products")
      .select("*, product_images(url, color_name), product_variants(color_name, size)")
      .eq("is_featured", true)
      .eq("status", "active")
      .limit(10);

    if (!error && data) {
      featuredProducts = data;
    } else if (error) {
      console.error("Error fetching featured products:", error);
    }
  } catch (error) {
    console.error("Error fetching featured products:", error);
  }

  const mappedFeaturedProducts = featuredProducts?.map(p => {
    const images = p.product_images?.map((img: any) => img.url) || [];

    // Extract unique colors with their first image
    const colorsMap = new Map<string, string>();
    if (p.product_variants) {
      p.product_variants.forEach((v: any) => {
        if (!colorsMap.has(v.color_name)) {
          const matchingImg = p.product_images?.find((img: any) => img.color_name === v.color_name);
          colorsMap.set(v.color_name, matchingImg?.url || images[0]);
        }
      });
    }

    const sizesSet = new Set<string>();
    if (p.product_variants) {
      p.product_variants.forEach((v: any) => {
        if (v.size) sizesSet.add(v.size);
      });
    }

    return {
      id: p.id,
      slug: p.slug,
      name: p.name,
      price: p.price,
      images,
      colors: Array.from(colorsMap.entries()).map(([name, image]) => ({ name, image })),
      sizes: Array.from(sizesSet),
      isNew: p.is_featured,
      isSale: (p.compare_at_price ?? 0) > p.price
    };
  }) || [];
  const instagramItems = sections?.filter(s => s.section_type === 'instagram').slice(0, 4).map((s, index) => ({
    id: s.id,
    url: s.image_url || "",
    link: s.button_link || 'https://instagram.com/tranquil.co.in',
    height: index % 2 === 0 ? 'h-[400px]' : 'h-[500px]'
  })) || [];

  // Fetch Reviews
  let dbReviews: any[] = [];
  try {
    const { data, error } = await supabase
      .from("reviews")
      .select("id, rating, title, comment, profiles(first_name, last_name, avatar_url), products(name)")
      .eq("status", "approved")
      .order("created_at", { ascending: false })
      .limit(4);
    if (data && !error) dbReviews = data;
  } catch (error) {
    console.error("Error fetching reviews:", error);
  }

  const realReviews = dbReviews?.map((r: any) => ({
    id: r.id,
    name: r.profiles ? `${r.profiles.first_name || ''} ${r.profiles.last_name || ''}`.trim() || 'Anonymous' : 'Anonymous',
    text: r.comment,
    product: r.products?.name,
    image: r.profiles?.avatar_url || "/images/avatar-1.jpg"
  })) || [];

  return (
    <>
      <HeroSection slides={heroSlides} />
      <TrendingMosaic collections={trendingEdits} />
      <BestSellers products={mappedBestSellers} />
      <ShopByCategory categories={mappedCategories} />
      <NewCollection initialData={mappedFeaturedProducts} />
      {editorialStories.length > 0 ? <FashionStories stories={editorialStories} /> : <FashionStories />}
      <Lookbook items={instagramItems} />
      {realReviews.length > 0 ? <Reviews reviews={realReviews} /> : <Reviews />}
      <VisitStore />
      <WhyChooseUs />
    </>
  );
}

import { notFound } from "next/navigation";
import { createClient } from "@/utils/supabase/server";
import ProductClient from "@/components/product/ProductClient";

interface ProductImage {
  url: string;
  color_name: string | null;
}

interface ProductVariant {
  color_name: string | null;
  color_hex: string | null;
  size: string | null;
  stock_quantity: number | null;
}

interface ProductCategory {
  category_id: string;
  categories: { name: string } | null;
}

interface Product {
  id: string;
  name: string;
  price: number;
  compare_at_price: number | null;
  slug: string;
  description: string | null;
  brand: string | null;
  fabric: string | null;
  tags: string[] | null;
  product_categories: ProductCategory[] | null;
  product_images: ProductImage[] | null;
  product_variants: ProductVariant[] | null;
}
export async function generateMetadata({ params }: { params: Promise<{ slug: string }> }) {
  const { slug } = await params;
  const decodedSlug = decodeURIComponent(slug);
  const supabase = await createClient();
  const { data: product } = await supabase
    .from("products")
    .select("name, description")
    .eq("slug", decodedSlug)
    .single();

  if (!product) {
    return {
      title: "Product Not Found",
    };
  }

  return {
    title: `${product.name} | Tranquil`,
    description: product.description,
  };
}

export default async function ProductDetailPage({ params }: { params: Promise<{ slug: string }> }) {
  const { slug } = await params;
  const decodedSlug = decodeURIComponent(slug);
  const supabase = await createClient();

  // 1. Fetch Product with images, variants, and category
  const { data: productData, error } = await supabase
    .from("products")
    .select(`
      *,
      product_categories(category_id, categories(name)),
      product_images(url, color_name),
      product_variants(color_name, color_hex, size, stock_quantity)
    `)
    .eq("slug", decodedSlug)
    .single<Product>();

  if (error || !productData) {
    notFound();
  }

  // 2. Fetch Related Products (same category)
  const { data: relatedData } = await supabase
    .from("products")
    .select(`
      id, name, price, compare_at_price, slug,
      product_categories!inner(category_id),
      product_images(url, color_name),
      product_variants(color_name, size)
    `)
    .eq("product_categories.category_id", productData.product_categories?.[0]?.category_id || "")
    .neq("id", productData.id)
    .limit(12);

  // 3. Format product for Client Component
  const colorImages: Record<string, string[]> = {};
  const images = productData.product_images?.map((img: ProductImage) => {
    if (img.color_name) {
      if (!colorImages[img.color_name]) colorImages[img.color_name] = [];
      colorImages[img.color_name].push(img.url);
    }
    return img.url;
  }) || [];
  
  if (images.length === 0) {
    images.push("https://images.unsplash.com/photo-1595777457583-95e059d581b8?q=80&w=1200"); // Fallback
    colorImages["Default"] = [...images];
  }

  // Extract unique colors
  const colorMap = new Map();
  productData.product_variants?.forEach((variant: ProductVariant) => {
    if (variant.color_name && variant.color_hex && !colorMap.has(variant.color_name)) {
      colorMap.set(variant.color_name, { name: variant.color_name, hex: variant.color_hex });
    }
  });
  const colors = Array.from(colorMap.values());

  // Extract unique sizes
  const sizesSet = new Set<string>();
  productData.product_variants?.forEach((variant: ProductVariant) => {
    if (variant.size) sizesSet.add(variant.size);
  });
  const sizes = Array.from(sizesSet);
  sizes.push("Custom"); // Always allow Custom sizing for this luxury brand

  const formattedProduct = {
    id: productData.id,
    name: productData.name,
    price: productData.price,
    compare_at_price: productData.compare_at_price || undefined,
    category: (productData.product_categories && productData.product_categories.length > 0 && productData.product_categories[0].categories) ? productData.product_categories[0].categories.name : "Clothing",
    description: productData.description || "",
    images,
    colorImages,
    colors,
    sizes,
    variants: (productData.product_variants || []).map((v: ProductVariant) => ({
      color_name: v.color_name || '',
      size: v.size || '',
      stock_quantity: v.stock_quantity || 0,
    })),
    brand: productData.brand || undefined,
    fabric: productData.fabric || undefined,
    tags: productData.tags || undefined,
    details: ["Dry clean only", "Handle with care"],
  };

  const formattedRelated = relatedData?.map((rp: any) => {
    const images = rp.product_images?.map((img: ProductImage) => img.url) || [];
    
    const colorsMap = new Map<string, string>();
    if (rp.product_variants) {
      rp.product_variants.forEach((v: ProductVariant) => {
        if (v.color_name && !colorsMap.has(v.color_name)) {
          const matchingImg = rp.product_images?.find((img: ProductImage) => img.color_name === v.color_name);
          colorsMap.set(v.color_name, matchingImg?.url || images[0]);
        }
      });
    }

    const sizesSet = new Set<string>();
    if (rp.product_variants) {
      rp.product_variants.forEach((v: ProductVariant) => {
        if (v.size) sizesSet.add(v.size);
      });
    }

    return {
      id: rp.id,
      name: rp.name,
      price: rp.price,
      slug: rp.slug,
      compare_at_price: rp.compare_at_price || undefined,
      isSale: (rp.compare_at_price ?? 0) > rp.price,
      images: images,
      colors: Array.from(colorsMap.entries()).map(([name, image]) => ({ name, image })),
      sizes: Array.from(sizesSet)
    };
  }) || [];

  const jsonLd = {
    "@context": "https://schema.org",
    "@type": "Product",
    "name": formattedProduct.name,
    "image": formattedProduct.images[0],
    "description": formattedProduct.description,
    "sku": formattedProduct.id,
    "offers": {
      "@type": "Offer",
      "priceCurrency": "INR",
      "price": formattedProduct.price,
      "availability": formattedProduct.variants.reduce((acc, v) => acc + v.stock_quantity, 0) > 0 ? "https://schema.org/InStock" : "https://schema.org/OutOfStock"
    }
  };

  return (
    <>
      <script
        type="application/ld+json"
        dangerouslySetInnerHTML={{ __html: JSON.stringify(jsonLd) }}
      />
      <ProductClient 
        product={formattedProduct} 
        relatedProducts={formattedRelated} 
      />
    </>
  );
}

"use client";

import { useState } from "react";
